func  (this *ModetradeCore) ParsePosition(position any, optionalArgs ...any) any  {
    //
    // {
    //     "IMR_withdraw_orders": 0.1,
    //     "MMR_with_orders": 0.05,
    //     "average_open_price": 27908.14386047,
    //     "cost_position": -139329.358492,
    //     "est_liq_price": 117335.92899428,
    //     "fee_24_h": 123,
    //     "imr": 0.1,
    //     "last_sum_unitary_funding": 70.38,
    //     "mark_price": 27794.9,
    //     "mmr": 0.05,
    //     "pending_long_qty": 123,
    //     "pending_short_qty": 123,
    //     "pnl_24_h": 123,
    //     "position_qty": -5,
    //     "settle_price": 27865.8716984,
    //     "symbol": "PERP_BTC_USDC",
    //     "timestamp": 1685429350571,
    //     "unsettled_pnl": 354.858492
    // }
    //
    market := GetArg(optionalArgs, 0, nil)
    _ = market
    var contract any = this.SafeString(position, "symbol")
    market = this.SafeMarket(contract, market)
    var size any = this.SafeString(position, "position_qty")
    var side any = nil
    if IsTrue(Precise.StringGt(size, "0")) {
        side = "long"
    } else {
        side = "short"
    }
    var contractSize any = this.SafeString(market, "contractSize")
    var markPrice any = this.SafeString(position, "mark_price")
    var timestamp any = this.SafeInteger(position, "timestamp")
    var entryPrice any = this.SafeString(position, "average_open_price")
    var unrealisedPnl any = this.SafeString(position, "unsettled_pnl")
    size = Precise.StringAbs(size)
    var notional any = Precise.StringMul(size, markPrice)
    return this.SafePosition(map[string]any {
        "info": position,
        "id": nil,
        "symbol": this.SafeString(market, "symbol"),
        "timestamp": timestamp,
        "datetime": this.Iso8601(timestamp),
        "lastUpdateTimestamp": nil,
        "initialMargin": nil,
        "initialMarginPercentage": nil,
        "maintenanceMargin": nil,
        "maintenanceMarginPercentage": nil,
        "entryPrice": this.ParseNumber(entryPrice),
        "notional": this.ParseNumber(notional),
        "leverage": nil,
        "unrealizedPnl": this.ParseNumber(unrealisedPnl),
        "contracts": this.ParseNumber(size),
        "contractSize": this.ParseNumber(contractSize),
        "marginRatio": nil,
        "liquidationPrice": this.SafeNumber(position, "est_liq_price"),
        "markPrice": this.ParseNumber(markPrice),
        "lastPrice": nil,
        "collateral": nil,
        "marginMode": "cross",
        "marginType": nil,
        "side": side,
        "percentage": nil,
        "hedged": nil,
        "stopLossPrice": nil,
        "takeProfitPrice": nil,
    })
}
